SELECT p.*, ste.site_nm AS site_nm, cd_pt.code_label AS prop_type_cd_nm FROM sy_prop p LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PROP_TYPE' AND cd_pt.code_value = p.prop_type_cd
ORDER BY p.prop_id ASC ORDER BY p.prop_id DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

