ORDER BY p.prop_id ASC ORDER BY p.prop_id DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE sy_prop
site_id = #{siteId}, disp_path = #{dispPath}, prop_key = #{propKey}, prop_value = #{propValue}, prop_label = #{propLabel}, prop_type_cd = #{propTypeCd}, sort_ord = #{sortOrd}, use_yn = #{useYn}, prop_remark = #{propRemark}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE prop_id = #{propId}
